import { Col, Form, Input, InputNumber, Row, Select, Spin } from "antd"
import { lazy, Suspense, useEffect, useState, useTransition } from "react"
import { useSelector } from "react-redux"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import { SYSTEM_KEY } from "src/constants/constants"
import { getRegexEmail, getRegexMobile } from "src/lib/stringsUtils"
import { getListComboByKey } from "src/lib/utils"
import ContactService from "src/services/Contacts"
import PropTypes from "prop-types"

// Lazy-load component cây
const LazyListOrg = lazy(() =>
  import("../../OrganizationContact/components/ListOrganization"),
)
const ModalInsertUnit = ({
  open,
  onCancel,
  onOk,
  AccountType,
  isEdit,
  listGroup,
}) => {
  const [form] = Form.useForm()
  const { listSystemKey } = useSelector(state => state?.appGlobal)
  const [loading, setLoading] = useState(false)
  const [listParent, setListParent] = useState([])
  const [organizationSelect, setOrganizationSelect] = useState()
  const [showOrg, setShowOrg] = useState(false) // state điều khiển khi nào mới mount cây
  const [isPending, startTransition] = useTransition()

  useEffect(() => {
    if (open) {
      setShowOrg(false)
      setTimeout(() => {
        startTransition(() => {
          setShowOrg(true)
        })
      }, 100)
    } else {
      setShowOrg(false)
    }
  }, [open, startTransition])

  useEffect(() => {
    if (organizationSelect) {
      form.setFieldsValue({ ParentID: organizationSelect.key })
    }
  }, [organizationSelect, form])

  const handleSubmit = () => {
    form.validateFields().then(values => {
      setLoading(true)
      ContactService[isEdit ? "updateByAccountID" : "insertAccount"]({
        ...values,
        AccountID: isEdit && isEdit.AccountID,
        AccountType: AccountType,
        ParentID: organizationSelect?.key || undefined,
      })
        .then(res => {
          if (res?.isOk) {
            Notice({ msg: `${isEdit ? "Cập nhật" : "Thêm mới"} thành công.` })
            onOk()
            onCancel()
          }
        })
        .finally(() => setLoading(false))
    })
  }
  const getListParent = () => {
    setLoading(true)
    ContactService?.getChildAccountByParentID({})
      .then(res => {
        if (res?.isError) return
        setListParent(res?.Object)
      })
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    getListParent()
  }, [AccountType])

  useEffect(() => {
    if (isEdit) {
      setOrganizationSelect({ key: isEdit?.ParentID })
      form.setFieldsValue(isEdit)
    } else
      form.setFieldsValue({
        Status: 1,
      })
  }, [])

  const renderFooter = () => (
    <div className="d-flex-end">
      <Button
        btnType="primary"
        className="btn-hover-shadow"
        onClick={handleSubmit}
      >
        Ghi lại
      </Button>
    </div>
  )

  return (
    <CustomModal
      title={`${isEdit ? "Cập nhật" : "Thêm"} đơn vị`}
      open={open}
      width="900px"
      onCancel={onCancel}
      footer={renderFooter()}
      style={{ paddingTop: "5%"}}
    >
      <Spin spinning={loading}>
        <Form form={form} layout="vertical">
          <Row gutter={16}>
            <Col span={24}>
              <Form.Item label="Nhóm đơn vị" name="GroupID">
                <Select placeholder="--chọn nhóm--">
                  {listGroup?.map(i => (
                    <Select.Option key={i?.GroupID} value={i?.GroupID}>
                      {i?.GroupName}
                    </Select.Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={24}>
              {/* <Form.Item
                label="Đơn vị cha"
                name="ParentID"
                rules={[
                  {
                    required: true,
                    message: "Chưa chọn nhóm đơn vị!",
                  },
                ]}
              >
                <Select placeholder="--chọn đơn vị cha--" allowClear>
                  {listParent?.map(i => (
                    <Select.Option key={i?.AccountID} value={i?.AccountID}>
                      {i?.AccountName}
                    </Select.Option>
                  ))}
                </Select>
              </Form.Item> */}
              <Form.Item
                label="Đơn vị cha"
                name="ParentID"
                rules={[{ required: true, message: "Chưa chọn đơn vị cha!" }]}
              >
                <div
                  style={{
                    maxHeight: open ? 200 : 0,
                    overflowY: "hidden",
                    transition: "max-height 0.3s ease",
                  }}
                >
                  {showOrg ? (
                    <Suspense
                      fallback={
                        <Spin style={{ display: "block", margin: "auto" }} />
                      }
                    >
                      <LazyListOrg
                        organizationSelect={organizationSelect}
                        setOrganizationSelect={setOrganizationSelect}
                      />
                    </Suspense>
                  ) : null}
                </div>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                label="Cấp"
                name="UnitLevel"
                rules={[
                  {
                    required: true,
                    message: "Chưa chọn nhóm đơn vị!",
                  },
                ]}
              >
                <Select placeholder="chọn trạng thái">
                  {getListComboByKey(
                    SYSTEM_KEY?.UNIT_LEVEL,
                    listSystemKey,
                  )?.map(i => (
                    <Select.Option key={+i?.CodeValue} value={+i?.CodeValue}>
                      {i?.Description}
                    </Select.Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                label="Tên đơn vị"
                name="AccountName"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <Input placeholder="Nhập tên đơn vị" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item label="Đường dẫn" name="Path">
                <Input placeholder="https://" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="Số điện thoại"
                name="PhoneNumber"
                rules={[
                  {
                    pattern: getRegexMobile(),
                    message: "Số điện thoại là chuỗi từ 8 đến 15 kí tự chữ số",
                  },
                ]}
              >
                <Input placeholder="Nhập số điện thoại" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                label="Email"
                name="Email"
                rules={[
                  {
                    pattern: getRegexEmail(),
                    message: "Email sai định dạng",
                  },
                ]}
              >
                <Input placeholder="Nhập email" />
              </Form.Item>
            </Col>
            {/* <Col span={24}>
              <SelectAddress
                floating={false}
                form={form}
                initValue={useMemo(
                  () => ({
                    provinceId: isEdit?.ProvinceID,
                    districtId: isEdit?.DistrictID,
                    wardId: isEdit?.WardID,
                  }),
                  [],
                )}
                onBeforeLoading={() => setLoading(true)}
                onLoadingSuccuss={() => setLoading(false)}
              />
            </Col> */}
            <Col span={24}>
              <Form.Item label="Địa chỉ" name="Address">
                <Input placeholder="Nhập địa chỉ" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item label="Trạng thái" name="Status">
                <Select placeholder="chọn trạng thái">
                  {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(
                    i => (
                      <Select.Option key={+i?.CodeValue} value={+i?.CodeValue}>
                        {i?.Description}
                      </Select.Option>
                    ),
                  )}
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item label="Thứ tự" name="SortOrder">
                <InputNumber
                  placeholder="Nhập số"
                  className="ant-input-number_no_arrow"
                />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Spin>
    </CustomModal>
  )
}

export default ModalInsertUnit

ModalInsertUnit.propTypes = {
  open: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
  onOk: PropTypes.func.isRequired,
  AccountType: PropTypes.string.isRequired,
  isEdit: PropTypes.bool.isRequired,
  listGroup: PropTypes.array.isRequired,
}
