import {
  Col,
  Divider,
  InputNumber,
  Row,
  Select,
  Space,
  Splitter,
  Tooltip,
} from "antd"
import { saveAs } from "file-saver"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import Delete from "src/components/Modal/Delete"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import {
  COLOR_STATUS,
  GUIDE_EMPTY,
  hideOnSinglePage,
  SYSTEM_KEY,
} from "src/constants/constants"
import { getListComboByKey, renderButtonCircle } from "src/lib/utils"
import ContactsService from "src/services/Contacts"
import ModalDetail from "./components/ModalDetail"
import ModalInsertUnit from "./components/ModalInsertUnit"
import { UnitContactStyled } from "./styled"
import ListOrganization from "../OrganizationContact/components/ListOrganization"
import TitleCustom from "src/components/TitleCustom"
import Title from "antd/es/skeleton/Title"

const { Option } = Select

const UnitContacts = () => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [unitSelect, setUnitSelect] = useState()
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
    Status: 1,
    AccountType: 0,
  })

  const [textSearch, setTextSearch] = useState("")
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState()
  const [listGroup, setListGroup] = useState([])
  const [listSelect, setListSelect] = useState([])
  const [openModalDetail, setOpenModalDetail] = useState(undefined)
  const [openModalDelete, setOpenModalDelete] = useState(undefined)
  const [openInsert, setOpenInsert] = useState(false)
  const [isEdit, setIsEdit] = useState(undefined)

  useEffect(() => {
    if (pagination) getList()
  }, [pagination, unitSelect])

  useEffect(() => {
    getListGroup()
  }, [])

  const getList = async () => {
    try {
      setLoading(true)

      const isRootNode =
        unitSelect?.key === "00000000-0000-0000-0000-000000000000" ||
        unitSelect?.key === 0 ||
        !unitSelect?.key

      const res = await ContactsService.getAccount({
        ...pagination,
        TextSearch: textSearch,
        ParentAccountID: isRootNode
          ? "00000000-0000-0000-0000-000000000000"
          : unitSelect?.key,
      })

      if (res?.isError) return
      setListData(res?.Object)
    } catch (error) {
      console.error("Network error:", error)
    } finally {
      setLoading(false)
    }
  }

  const getListGroup = async () => {
    try {
      setLoading(true)
      const res = await ContactsService.getGroupAccount({
        PageSize: 20,
        CurrentPage: 1,
        TextSearch: "",
        Status: 1,
        Type: 7,
      })
      if (res?.isError) return
      setListGroup(res?.Object?.lstAccountGroupVM)
    } finally {
      setLoading(false)
    }
  }

  const deleteAccount = listID => {
    ContactsService.deleteAccount(listID).then(res => {
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Xóa thành công!",
      })
    })
  }

  const changeValueTable = (idx, object) =>
    setListData(pre => ({
      ...pre,
      lstAccountVM: pre?.lstAccountVM?.map((i, index) => {
        if (idx !== index) return i
        return { ...i, ...object }
      }),
    }))

  const updateOrders = () => {
    let listOrders = {
      Type: 1,
      lstListUpdateSortOrder: listData?.lstAccountVM.map(data => ({
        ID: data?.AccountID,
        SortOrder: data?.SortOrder,
      })),
    }
    ContactsService.updateSortOrder(listOrders).then(res => {
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Cập nhật vị trí thành công!",
      })
    })
  }

  const handleExport = () => {
    setLoading(true)
    ContactsService.exportUser({
      Status: pagination.Status,
      AccountType: pagination.AccountType,
      textSearch,
      ID: unitSelect?.key,
      AccountID:
        listSelect.length > 0
          ? listSelect.map(i => i.AccountID).toString()
          : undefined,
    })
      .then(res => {
        if (res.isError) return
        saveAs(res, "Danh_sach_don_vi.xlsx")
      })
      .finally(() => setLoading(false))
  }

  const columns = [
    {
      title: "Tên đơn vị",
      dataIndex: "AccountName",
      key: "AccountName",
      render: val =>
        val ? (
          <Tooltip title={val}>
            <div className="max-line2">{val}</div>
          </Tooltip>
        ) : (
          <span className="text-muted">Chưa có tên đơn vị</span>
        ),
    },
    {
      title: (
        <>
          <MainTableHeader>Email</MainTableHeader>
          <SubTableHeader>Số điện thoại</SubTableHeader>
        </>
      ),
      dataIndex: "PhoneNumber",
      key: "PhoneNumber",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{record?.Email}</MainTableData>
          <SubTableData>{val}</SubTableData>
        </>
      ),
    },
    {
      title: "Địa chỉ",
      dataIndex: "FullAddress",
      key: "FullAddress",
      render: val =>
        val ? (
          <Tooltip title={val}>
            <div className="max-line2">{val}</div>
          </Tooltip>
        ) : (
          <span className="text-muted">Chưa có địa chỉ</span>
        ),
    },
    {
      title: "Nhóm",
      dataIndex: "GroupName",
      key: "GroupName",
      render: val =>
        val ? (
          <Tooltip title={val}>
            <div className="max-line2">{val}</div>
          </Tooltip>
        ) : (
          <span className="text-muted">Chưa có nhóm</span>
        ),
    },
    {
      title: "Thứ tự",
      dataIndex: "SortOrder",
      key: `SortOrder`,
      align: "center",
      width: 100,
      render: (value, record, idx) => (
        <InputNumber
          className="ant-input-number_no_arrow"
          style={{ width: "100%" }}
          value={value}
          onChange={event =>
            changeValueTable(idx, {
              SortOrder: event,
            })
          }
        />
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: `Status`,
      align: "center",
      width: 140,
      render: (val, record) => (
        <div>
          <div
            className="fw-700 text-center"
            style={
              val === 1
                ? { color: COLOR_STATUS.active }
                : { color: COLOR_STATUS.inactive }
            }
          >
            {val === 1 ? "Kích hoạt" : "Vô hiệu"}
          </div>
          <FloatActionWrapper size="small" className="float-action__wrapper">
            {listData?.ButtonShow?.IsUpdate &&
              renderButtonCircle(
                "Chỉnh sửa",
                "edit",
                () => {
                  setIsEdit(record)
                  setOpenInsert(true)
                },
                true,
              )}
            {listData?.ButtonShow?.IsDelete &&
              renderButtonCircle(
                "Xoá",
                "bin",
                () => {
                  setOpenModalDelete(record)
                },
                true,
              )}
          </FloatActionWrapper>
        </div>
      ),
    },
  ]

  return (
    <UnitContactStyled>
      <Row gutter={[16, 16]}>
        <Col md={10} xs={24}>
          <InputCustom
            type="search"
            allowClear
            label="Nhập tên, SĐT đơn vị"
            onSearch={() => setPagination(pre => ({ ...pre, CurrentPage: 1 }))}
            onChange={e => setTextSearch(e?.target?.value)}
          />
        </Col>
        <Col lg={5} xs={24}>
          <SelectCustom
            label="Loại đơn vị"
            value={pagination.AccountType}
            onChange={AccountType => {
              setPagination(pre => ({
                ...pre,
                AccountType: AccountType,
                CurrentPage: 1,
                Status: 1,
              }))
              setListSelect([])
            }}
          >
            <Option key={0} value={0}>
              Tất cả
            </Option>
            {getListComboByKey(SYSTEM_KEY.UNIT_TYPE, listSystemKey)?.map(i => (
              <Select.Option value={+i.CodeValue} key={+i.CodeValue}>
                {i.Description}
              </Select.Option>
            ))}
          </SelectCustom>
        </Col>
        <Col lg={4} xs={24}>
          <SelectCustom
            label="Trạng thái"
            value={pagination.Status}
            onChange={Status => {
              setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
            }}
          >
            {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
              <Option key={+i.CodeValue} value={+i.CodeValue}>
                {i?.Description}
              </Option>
            ))}
          </SelectCustom>
        </Col>
        <Col lg={5} xs={24}>
          <SelectCustom
            label="Nhóm đơn vị"
            defaultValue={GUIDE_EMPTY}
            onChange={GroupID => {
              setPagination(pre => ({ ...pre, GroupID, CurrentPage: 1 }))
            }}
          >
            <Option key={GUIDE_EMPTY} value={GUIDE_EMPTY}>
              Tất cả
            </Option>
            {listGroup?.map(i => (
              <Option key={i.GroupID} value={i.GroupID}>
                {i?.GroupName}
              </Option>
            ))}
          </SelectCustom>
        </Col>
      </Row>

      <Divider className="mv-16" />
      <Row style={{ display: "flex", justifyContent: "space-between" }}>
        <TitleCustom className={"ml-10"}>
          Danh sách đơn vị ({listData?.total}) :
        </TitleCustom>
        <Space>
          {listData?.ButtonShow?.IsInsert && (
            <Button
              btnType="primary"
              className="btn-hover-shadow"
              onClick={() => setOpenInsert(true)}
            >
              Thêm mới
            </Button>
          )}
          {listData?.ButtonShow?.IsUpdate && (
            <Button btnType="primary" onClick={updateOrders}>
              Cập nhật vị trí
            </Button>
          )}
          {listData?.ButtonShow?.IsDelete && listSelect.length > 0 && (
            <Button
              btnType="primary"
              className="btn-hover-shadow"
              onClick={() =>
                setOpenModalDelete({
                  deleteAll: true,
                  AccountName: "Tất cả đơn vị đã chọn",
                  AccountID: listSelect.map(i => i?.AccountID),
                })
              }
            >
              Xóa nhiều
            </Button>
          )}
          {listData?.ButtonShow?.IsExport && (
            <Button
              btnType="third"
              className="btn-hover-shadow"
              onClick={handleExport}
            >
              Xuất Excel
            </Button>
          )}
        </Space>
      </Row>
      <Row gutter={16}>
        <Splitter>
          <Splitter.Panel defaultSize="18%" min="15%" max="45%">
            <Col style={{ width: 750 }}>
              <ListOrganization
                organizationSelect={unitSelect}
                setOrganizationSelect={setUnitSelect}
              />
            </Col>
          </Splitter.Panel>
          <Splitter.Panel>
            <TableCustom
              isPrimary
              rowSelection={{
                selectedRowKeys: listSelect?.map(i => i?.AccountID),
                onChange: (listKey, listItems) => {
                  setListSelect(listItems)
                },
                preserveSelectedRowKeys: true,
              }}
              dataSource={listData?.lstAccountVM}
              columns={columns}
              // sticky={{ offsetHeader: 52 }}
              loading={loading}
              textEmpty="Không có đơn vị nào!"
              pagination={{
                hideOnSinglePage: listData?.total <= hideOnSinglePage,
                current: pagination?.CurrentPage,
                pageSize: pagination?.PageSize,
                responsive: true,
                total: listData?.total,
                locale: { items_per_page: "" },
                showSizeChanger: listData?.total > 10,
                onChange: (CurrentPage, PageSize) => {
                  setPagination({
                    ...pagination,
                    CurrentPage,
                    PageSize,
                  })
                },
              }}
              rowKey="AccountID"
            />
          </Splitter.Panel>
        </Splitter>
      </Row>
      {!!openInsert && (
        <ModalInsertUnit
          open={openInsert}
          AccountType={pagination.AccountType}
          isEdit={isEdit}
          listGroup={listGroup}
          onCancel={() => {
            setOpenInsert(false)
            setIsEdit(undefined)
          }}
          onOk={getList}
        />
      )}
      {!!openModalDetail && (
        <ModalDetail
          open={openModalDetail}
          onCancel={() => {
            setOpenModalDetail(false)
          }}
        />
      )}
      {openModalDelete && (
        <Delete
          isOpen={!!openModalDelete}
          content={{
            title: (
              <div className="fw-600 text-center" style={{ fontSize: 16 }}>
                {`Bạn có chắc chắn muốn xóa "${(
                  <b>{openModalDelete?.AccountName}</b>
                )}" không?`}
              </div>
            ),
          }}
          onOk={() => {
            deleteAccount(
              openModalDelete?.deleteAll
                ? openModalDelete?.AccountID
                : [openModalDelete?.AccountID],
            )
            setOpenModalDelete(undefined)
          }}
          onCancel={() => setOpenModalDelete(undefined)}
        />
      )}
    </UnitContactStyled>
  )
}

export default UnitContacts
